mapper.select:
SELECT 
FROM invest_project
WHERE del_flag = '0'

    AND scheme_id = #{schemeId}


    AND scheme_name LIKE CONCAT('%', #{schemeName}, '%')


    AND project_code LIKE CONCAT('%', #{projectCode}, '%')


    AND project_name LIKE CONCAT('%', #{projectName}, '%')


    AND project_type = #{projectType}


    AND industry = #{industry}


    AND priority = #{priority}


    AND project_status = #{projectStatus}


    AND plan_year = #{planYear}


    AND dept_id = #{deptId}

ORDER BY create_time DESC, project_id DESC
